values
('spanish:g-2-adjectives-and-agreement:match:48fcfde7', 'spanish', 'spanish:g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “mi casa / mis libros”?", "options": ["blue (sing. / pl.)", "my house / my books", "the most interesting", "our family"]}'::jsonb, '{"answer": 1, "explain": "“mi casa / mis libros” means: my house / my books"}'::jsonb),
('spanish:g-2-adjectives-and-agreement:match:abe00c26', 'spanish', 'spanish:g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “nuestra familia”?", "options": ["better", "worse", "our family", "those shoes"]}'::jsonb, '{"answer": 2, "explain": "“nuestra familia” means: our family"}'::jsonb),
('spanish:g-2-adjectives-and-agreement:match:612faa25', 'spanish', 'spanish:g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “este libro”?", "options": ["the most interesting", "Spanish (m. / f.)", "this book", "better"]}'::jsonb, '{"answer": 2, "explain": "“este libro” means: this book"}'::jsonb),
('spanish:g-2-adjectives-and-agreement:match:98ea16ba', 'spanish', 'spanish:g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “esos zapatos”?", "options": ["my house / my books", "this book", "a big house", "those shoes"]}'::jsonb, '{"answer": 3, "explain": "“esos zapatos” means: those shoes"}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:21c94f7b', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen brothers", "I am nearly fifteen years old", "My friend is fifteen years old"]}'::jsonb, '{"answer": 0, "explain": "‘tengo quince años’ = I am fifteen (tener + años, not ‘to be’). The traps add a false subject or age detail."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:c492bf98', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Me levanto a las siete.\" data-listen></span><br>Listen. What time?", "options": ["seven o’clock", "seven thirty exactly", "quarter past seven", "seventeen o’clock"]}'::jsonb, '{"answer": 0, "explain": "‘a las siete’ = at seven. Every distractor is longer and invents a time detail that was not said."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:e9908f08', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"No puedo salir porque tengo que estudiar.\" data-listen></span><br>Listen. Why can’t they go out?", "options": ["because they have to study", "because they don’t want to study at all", "because they are already studying now", "because their parents will not allow it"]}'::jsonb, '{"answer": 0, "explain": "‘tengo que estudiar’ = I have to study. Every distractor is longer and changes the reason given."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:28543f1a', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "How do you say ‘I like sports’ (plural)?", "options": ["Me gustan los deportes", "Me gusta los deportes", "Me gusto los deportes", "Yo gusto mucho los deportes"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with the plural subject ‘los deportes’ → gustan. B fails to agree; C/D conjugate gustar as if it were a normal verb."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:4f7ef3ad', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "Careful — which sentence means ‘I am bored’ (right now)?", "options": ["Estoy aburrido", "Soy aburrido", "Tengo aburrido", "Hago aburrido"]}'::jsonb, '{"answer": 0, "explain": "A temporary feeling takes estar: estoy aburrido. ‘Soy aburrido’ would mean ‘I am a boring person’ — a classic trap."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:09652961', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "How do you say ‘I can’t sleep’?", "options": ["No puedo dormir", "No podo dormir", "No puedes dormir", "No puede dormir mucho"]}'::jsonb, '{"answer": 0, "explain": "poder is a stem-changer: puedo. ‘podo’ ignores the o→ue change; C/D use the wrong person."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:4e0e98dd', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me ducho antes de desayunar", "Ducho antes de desayunar cada mañana", "Yo ducho muy temprano siempre", "Se ducho antes de desayunar"]}'::jsonb, '{"answer": 0, "explain": "ducharse is reflexive: (yo) me ducho. Dropping ‘me’ or using the wrong pronoun is wrong."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:a9c9be73', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Voy a ___ mis deberes esta tarde.’", "options": ["hacer", "hago", "haciendo", "hecho"]}'::jsonb, '{"answer": 0, "explain": "‘ir a’ takes an infinitive → hacer. The others are conjugated / non-finite forms."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:80eb65b1', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "‘Prefiero el fútbol al baloncesto’ — which stem-change is this?", "options": ["e → ie (preferir → prefiero)", "o → ue (preferir → prefuero)", "e → i (preferir → prifiero)", "no change at all"]}'::jsonb, '{"answer": 0, "explain": "preferir is an e→ie stem-changer: prefiero, prefieres, prefiere…"}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:mcq:52a5cb73', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'mcq', 'mcq', 1, '{"question": "‘¿Dónde está el gimnasio?’ uses ‘está’ because…", "options": ["it asks about location, which always takes estar", "location questions always use ‘ser’ instead of estar", "‘gimnasio’ is a feminine noun", "it is describing a permanent personality trait"]}'::jsonb, '{"answer": 0, "explain": "Location questions always use estar: ¿dónde está…?"}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:1807f2d2', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘gustar’ works backwards — the verb agrees with the thing liked, not the person."}'::jsonb, '{"answer": true, "explain": "Me gusta el fútbol / me gustan los deportes — the verb matches the thing liked."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:2280a2e3', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘Soy aburrido’ and ‘Estoy aburrido’ mean exactly the same thing."}'::jsonb, '{"answer": false, "explain": "Soy aburrido = I am a boring person (ser, permanent). Estoy aburrido = I am bored right now (estar, temporary)."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:f7c7aa64', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘tener que’ is followed by an infinitive."}'::jsonb, '{"answer": true, "explain": "tengo que estudiar / trabajar / dormir — always an infinitive."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:5694ecf4', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘poder’ changes e → ie in the present tense."}'::jsonb, '{"answer": false, "explain": "poder changes o → ue: puedo, puedes, puede, podemos, podéis, pueden."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:c09fc47b', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "For location (where something is) you use ‘estar’, not ‘ser’."}'::jsonb, '{"answer": true, "explain": "está en Madrid, not es en Madrid."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:35f19f44', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘nosotros’ and ‘vosotros’ keep the regular stem in radical-changing verbs."}'::jsonb, '{"answer": true, "explain": "queremos, podemos, pedimos — the nosotros/vosotros forms do NOT change the stem."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:b2e89e9b', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘ducharse’ is a reflexive verb, so ‘I shower’ is ‘me ducho’."}'::jsonb, '{"answer": true, "explain": "Reflexive: me ducho, te duchas, se ducha."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:tf:3a802483', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'tf', 'tf', 1, '{"question": "‘voy a’ + infinitive describes something you did in the past."}'::jsonb, '{"answer": false, "explain": "ir a + infinitive = near future (going to…), not the past."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:e641e534', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "How do regular -ar, -er, -ir verbs work?", "reading": "<p>The present tense describes what happens now or generally. Remove the -ar/-er/-ir ending and add the pattern endings. Model verb <span data-say=\"hablar\">hablar</span> (to speak):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablo\">hablo</span></td><td>I speak</td><td><span data-say=\"hablamos\">hablamos</span></td><td>we speak</td></tr>\n              <tr><td><span data-say=\"hablas\">hablas</span></td><td>you speak</td><td><span data-say=\"habláis\">habláis</span></td><td>you all speak</td></tr>\n              <tr><td><span data-say=\"habla\">habla</span></td><td>he/she speaks</td><td><span data-say=\"hablan\">hablan</span></td><td>they speak</td></tr>\n            </table>\n            <p>-er verbs like <span data-say=\"comer\">comer</span> (to eat): <span data-say=\"como, comes, come, comemos, coméis, comen\">como, comes, come, comemos, coméis, comen</span>. -ir verbs like <span data-say=\"vivir\">vivir</span> (to live): <span data-say=\"vivo, vives, vive, vivimos, vivís, viven\">vivo, vives, vive, vivimos, vivís, viven</span>.</p>\n            <p>Model sentence: <span data-say=\"Vivo en Madrid y hablo dos idiomas.\">Vivo en Madrid y hablo dos idiomas.</span> — <em>I live in Madrid and I speak two languages.</em></p>", "question": "What is the ‘yo’ (I) ending for a regular -ir verb like ‘vivir’?", "options": ["-o (vivo)", "-as (vivas)", "-amos (vivamos)", "-en (viven)"]}'::jsonb, '{"answer": 0, "explain": "Regular -ar, -er and -ir verbs all take -o for ‘yo’: vivo, como, hablo."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:ad87ead4', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "ser vs estar — two verbs for ‘to be’", "reading": "<p>Spanish has two verbs for ‘to be’ and examiners test the difference constantly.</p>\n            <p><strong>ser</strong> — permanent/identity: <span data-say=\"soy, eres, es, somos, sois, son\">soy, eres, es, somos, sois, son</span>. Use for personality, nationality, jobs, time: <span data-say=\"Soy alta y soy española.\">Soy alta y soy española.</span> (I am tall and I am Spanish.)</p>\n            <p><strong>estar</strong> — temporary state/location: <span data-say=\"estoy, estás, está, estamos, estáis, están\">estoy, estás, está, estamos, estáis, están</span>. Use for feelings, mood, position: <span data-say=\"Estoy cansado porque estoy en el gimnasio.\">Estoy cansado porque estoy en el gimnasio.</span> (I am tired because I am at the gym.)</p>\n            <p>Compare: <span data-say=\"Es aburrido.\">Es aburrido.</span> (He is a boring person) vs <span data-say=\"Está aburrido.\">Está aburrido.</span> (He is bored right now).</p>", "question": "Which verb do you use to say WHERE something is located?", "options": ["estar (está en Madrid)", "ser (es en Madrid)", "tener (tiene en Madrid)", "hacer (hace en Madrid)"]}'::jsonb, '{"answer": 0, "explain": "Location always uses estar: está en Madrid. ‘ser en’ is a very common wrong-verb error."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:a27e8709', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "tener, ir, hacer — three essential irregulars", "reading": "<p>These three verbs appear in almost every exam answer.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tener\">tener</span></td><td>to have</td><td><span data-say=\"tengo, tienes, tiene, tenemos, tenéis, tienen\">tengo, tienes, tiene…</span></td></tr>\n              <tr><td><span data-say=\"ir\">ir</span></td><td>to go</td><td><span data-say=\"voy, vas, va, vamos, vais, van\">voy, vas, va…</span></td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td>to do/make</td><td><span data-say=\"hago, haces, hace, hacemos, hacéis, hacen\">hago, haces, hace…</span></td></tr>\n            </table>\n            <p>Remember <span data-say=\"tener que + infinitivo\">tener que + infinitive</span> (to have to) and <span data-say=\"ir a + infinitivo\">ir a + infinitive</span> (going to, near future): <span data-say=\"Tengo quince años y voy a hacer mis deberes.\">Tengo quince años y voy a hacer mis deberes.</span> — <em>I am fifteen and I am going to do my homework.</em></p>", "question": "How do you say ‘I have to study’?", "options": ["Tengo que estudiar", "Tengo estudiar", "Voy que estudiar", "Tengo que estudiando"]}'::jsonb, '{"answer": 0, "explain": "tener que + infinitive = to have to study. B is missing ‘que’; C uses the wrong verb; D wrongly uses the gerund instead of the infinitive."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:32a57f4e', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "Radical-changing (stem-changing) verbs", "reading": "<p>Some verbs change their stem vowel in ALL forms EXCEPT <strong>nosotros</strong> and <strong>vosotros</strong>. The endings stay regular.</p>\n            <ul>\n              <li><strong>e → ie</strong>: <span data-say=\"querer\">querer</span> (to want) → <span data-say=\"quiero, quieres, quiere, queremos, queréis, quieren\">quiero, quieres, quiere…</span>; <span data-say=\"preferir\">preferir</span> → <span data-say=\"prefiero\">prefiero</span></li>\n              <li><strong>o → ue</strong>: <span data-say=\"poder\">poder</span> (to be able to) → <span data-say=\"puedo, puedes, puede, podemos, podéis, pueden\">puedo, puedes, puede…</span>; <span data-say=\"dormir\">dormir</span> → <span data-say=\"duermo\">duermo</span></li>\n              <li><strong>e → i</strong>: <span data-say=\"pedir\">pedir</span> (to ask for) → <span data-say=\"pido, pides, pide, pedimos, pedís, piden\">pido, pides, pide…</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Example: <span data-say=\"No puedo salir porque quiero dormir.\">No puedo salir porque quiero dormir.</span> — <em>I can’t go out because I want to sleep.</em></p>", "question": "Why is ‘puedo’ correct and ‘podo’ wrong for ‘I can’?", "options": ["poder is a stem-changer: o → ue in ‘yo’", "podo is simply an alternative spelling of puedo", "podo is used only in the plural form", "puedo is only used with ‘nosotros’"]}'::jsonb, '{"answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:aeb4de87', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "Reflexive verbs in the present", "reading": "<p>Reflexive verbs describe an action you do to yourself and need a pronoun (<strong>me, te, se, nos, os, se</strong>) before the verb.</p>\n            <p><span data-say=\"levantarse\">levantarse</span> (to get up): <span data-say=\"me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan\">me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan</span>.</p>\n            <p>Other common ones: <span data-say=\"ducharse\">ducharse</span> (to shower), <span data-say=\"vestirse\">vestirse</span> (to get dressed) <span class=\"tier-h\">H</span>, <span data-say=\"acostarse\">acostarse</span> (to go to bed).</p>\n            <p>Example: <span data-say=\"Me levanto a las siete y me ducho enseguida.\">Me levanto a las siete y me ducho enseguida.</span> — <em>I get up at seven and I shower straight away.</em></p>", "question": "What is missing from ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "the accent on the final letter of the verb", "the linking word ‘que’ placed before the verb", "the article ‘el’"]}'::jsonb, '{"answer": 0, "explain": "levantarse is reflexive: you must include me/te/se — ‘me levanto’."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:learn:97bc1607', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'learn', 'mcq', 1, '{"readingTitle": "gustar-type verbs", "reading": "<p><span class=\"tier-h\">H</span> Verbs like <strong>gustar</strong> (to like) work backwards — the thing liked is the subject, so the verb agrees with IT, not with the person.</p>\n            <ul>\n              <li>ONE thing liked → <span data-say=\"me gusta\">me gusta</span>: <span data-say=\"Me gusta el fútbol.\">Me gusta el fútbol.</span> (I like football.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me gustan\">me gustan</span>: <span data-say=\"Me gustan los deportes.\">Me gustan los deportes.</span> (I like sports.)</li>\n            </ul>\n            <p>Other verbs behaving the same way: <span data-say=\"interesar\">interesar</span> (to interest), <span data-say=\"encantar\">encantar</span> (to love — Me encanta…), <span data-say=\"doler\">doler</span> (to hurt) <span class=\"tier-h\">H</span>.</p>", "question": "Why is it ‘Me gustan las matemáticas’ and not ‘Me gusta las matemáticas’?", "options": ["‘las matemáticas’ is plural, so the verb is plural", "gustar is always plural in Spanish regardless of the subject", "‘matemáticas’ is a masculine noun", "it describes a future plan"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with the thing liked; ‘las matemáticas’ is plural → gustan (gustar is not always plural)."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:misc:d6201700', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Me gusta los deportes.</p><p><strong>✅ The correct idea:</strong> Me gustan los deportes.</p>", "question": "Why is ‘Me gusta los deportes’ wrong?", "options": ["‘los deportes’ is plural, so it must be ‘gustan’", "you must always put the verb ‘estar’ in front of it too", "‘deportes’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with the thing liked; plural subject → gustan."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:misc:cb75c663', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Soy aburrido. (= I am bored right now)</p><p><strong>✅ The correct idea:</strong> Estoy aburrido. (= I am bored right now)</p>", "question": "Which verb correctly says ‘I am bored right now’?", "options": ["Estoy aburrido — a temporary feeling uses estar", "Soy aburrido — feelings always use ser instead of estar", "Tengo aburrido — feelings use tener", "Hago aburrido — feelings use hacer"]}'::jsonb, '{"answer": 0, "explain": "Temporary feelings and moods take estar, not ser. ‘Soy aburrido’ describes a permanent personality trait instead."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:misc:4ae1ce0c', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Yo podo dormir mucho.</p><p><strong>✅ The correct idea:</strong> Yo puedo dormir mucho.</p>", "question": "Why is ‘podo’ wrong here?", "options": ["poder is a stem-changer: o → ue in ‘yo’ → puedo", "podo is simply an alternative spelling of puedo", "podo is only used in the plural form", "puedo is only used with ‘nosotros’"]}'::jsonb, '{"answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}'::jsonb),
('spanish:g-3-present-tense-and-key-irregulars:misc:d1980b0a', 'spanish', 'spanish:g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Levanto a las siete.</p><p><strong>✅ The correct idea:</strong> Me levanto a las siete.</p>", "question": "What is missing in ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "an accent on the final letter of the verb form", "the linking word ‘a’", "the article ‘el’"]}'::jsonb, '{"answer": 0, "explain": "levantarse is reflexive: you need me/te/se — ‘me levanto’."}'::jsonb),
